// TestTransformerRoundTrip tests the basic round-trip encryption/decryption of a simple transformer.
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name        string
		data        []byte
		dataCtx     Context
		transformer Transformer
		expectErr   bool
	}{
		{
			name:        "successful round-trip with empty data",
			data:        []byte{},
			dataCtx:     DefaultContext([]byte("key")),
			transformer: &testTransformer{to: []byte("encrypted"), from: []byte{}},
			expectErr:   false,
		},
		{
			name:        "successful round-trip with valid data",
			data:        []byte("secret data"),
			dataCtx:     DefaultContext([]byte("auth-data")),
			transformer: &testTransformer{to: []byte("encrypted-data"), from: []byte("secret data")},
			expectErr:   false,
		},
		{
			name:        "successful round-trip with nil context",
			data:        []byte("sensitive"),
			dataCtx:     nil,
			transformer: &testTransformer{to: []byte("cipher"), from: []byte("sensitive")},
			expectErr:   false,
		},
		{
			name:        "encryption error",
			data:        []byte("data"),
			dataCtx:     DefaultContext([]byte("ctx")),
			transformer: &testTransformer{err: fmt.Errorf("encryption failed")},
			expectErr:   true,
		},
		{
			name:        "decryption error",
			data:        []byte("data"),
			dataCtx:     DefaultContext([]byte("ctx")),
			transformer: &testTransformer{to: []byte("encrypted"), err: fmt.Errorf("decryption failed")},
			expectErr:   true,
		},
	}

	ctx := context.Background()
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Test encryption (write to storage)
			encrypted, errWrite := tt.transformer.TransformToStorage(ctx, tt.data, tt.dataCtx)
			if (errWrite != nil) != tt.expectErr {
				t.Fatalf("TransformToStorage unexpected error: got %v, want %v", errWrite != nil, tt.expectErr)
			}

			if tt.expectErr {
				return // skip decryption test on write error
			}

			// Test decryption (read from storage)
			decrypted, stale, errRead := tt.transformer.TransformFromStorage(ctx, encrypted, tt.dataCtx)
			if errRead != nil {
				t.Fatalf("TransformFromStorage unexpected error: %v", errRead)
			}

			// Verify round-trip
			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("round-trip failed: got %q, want %q", string(decrypted), string(tt.data))
			}

			if stale {
				t.Errorf("expected stale=false for first transformer, got true")
			}
		})
	}
}

// TestDefaultContext tests the DefaultContext implementation.
func TestDefaultContext(t *testing.T) {
	tests := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "empty context",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "simple context",
			data:     []byte("context-data"),
			expected: []byte("context-data"),
		},
		{
			name:     "binary context",
			data:     []byte{0x00, 0x01, 0x02, 0xFF},
			expected: []byte{0x00, 0x01, 0x02, 0xFF},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := DefaultContext(tt.data)
			authenticated := ctx.AuthenticatedData()

			if !bytes.Equal(authenticated, tt.expected) {
				t.Errorf("AuthenticatedData() = %v, want %v", authenticated, tt.expected)
			}
		})
	}
}

// TestPrefixTransformerWithValidPrefix tests PrefixTransformer with matching prefix.
func TestPrefixTransformerWithValidPrefix(t *testing.T) {
	tests := []struct {
		name              string
		prefix            []byte
		data              []byte
		expectedEncrypted []byte
		expectedDecrypted []byte
		expectErr         bool
	}{
		{
			name:              "single byte prefix",
			prefix:            []byte("A"),
			data:              []byte("value"),
			expectedEncrypted: []byte("Aencrypted"),
			expectedDecrypted: []byte("value"),
			expectErr:         false,
		},
		{
			name:              "multi-byte prefix",
			prefix:            []byte("k8s:enc:aes:"),
			data:              []byte("secret"),
			expectedEncrypted: []byte("k8s:enc:aes:cipher"),
			expectedDecrypted: []byte("secret"),
			expectErr:         false,
		},
		{
			name:              "empty data with prefix",
			prefix:            []byte("prefix:"),
			data:              []byte{},
			expectedEncrypted: []byte("prefix:"),
			expectedDecrypted: []byte{},
			expectErr:         false,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			testTransformer := &testTransformer{
				from: tt.expectedDecrypted,
				to:   []byte("cipher"), // the part after the prefix
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: tt.prefix, Transformer: testTransformer},
			)

			// Test encryption with prefix
			encrypted, err := prefixTrans.TransformToStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			if !bytes.Equal(encrypted, tt.expectedEncrypted) {
				t.Errorf("encrypted = %v, want %v", encrypted, tt.expectedEncrypted)
			}

			// Test decryption with prefix
			decrypted, stale, err := prefixTrans.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(decrypted, tt.expectedDecrypted) {
				t.Errorf("decrypted = %v, want %v", decrypted, tt.expectedDecrypted)
			}

			if stale {
				t.Errorf("expected stale=false for matching first prefix, got true")
			}
		})
	}
}

// TestPrefixTransformerMismatchedPrefix tests error handling for mismatched prefixes.
func TestPrefixTransformerMismatchedPrefix(t *testing.T) {
	tests := []struct {
		name              string
		configuredPrefix  []byte
		incomingData      []byte
		customErr         error
		expectErr         bool
		expectErrMessage  string
	}{
		{
			name:             "data without matching prefix",
			configuredPrefix: []byte("k8s:"),
			incomingData:     []byte("unencrypted-value"),
			customErr:        fmt.Errorf("no matching transformer"),
			expectErr:        true,
			expectErrMessage: "no matching transformer",
		},
		{
			name:             "empty data with prefix configured",
			configuredPrefix: []byte("prefix:"),
			incomingData:     []byte{},
			customErr:        fmt.Errorf("empty data"),
			expectErr:        true,
			expectErrMessage: "empty data",
		},
		{
			name:              "default error when none provided",
			configuredPrefix:  []byte("specific:"),
			incomingData:      []byte("other:data"),
			customErr:         nil,
			expectErr:         true,
			expectErrMessage:  "does not match any of the supported transformers",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			testTransformer := &testTransformer{
				from: []byte("decrypted"),
			}

			prefixTrans := NewPrefixTransformers(
				tt.customErr,
				PrefixTransformer{Prefix: tt.configuredPrefix, Transformer: testTransformer},
			)

			decrypted, _, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if !tt.expectErr {
				t.Fatalf("expected error, got nil")
			}

			if err == nil {
				t.Fatalf("expected error with message containing %q", tt.expectErrMessage)
			}

			if decrypted != nil {
				t.Errorf("expected nil result on error, got %v", decrypted)
			}
		})
	}
}

// TestMultiplePrefixTransformers tests transformer union with multiple prefixes.
func TestMultiplePrefixTransformers(t *testing.T) {
	tests := []struct {
		name           string
		transformers   []PrefixTransformer
		incomingData   []byte
		expectedIndex  int
		expectedStale  bool
		expectErr      bool
	}{
		{
			name: "first transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("first:encrypted"),
			expectedIndex: 0,
			expectedStale: false,
		},
		{
			name: "second transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("second:encrypted"),
			expectedIndex: 1,
			expectedStale: true, // stale because not using first transformer
		},
		{
			name: "no transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("third:encrypted"),
			expectedIndex: -1,
			expectErr:     true,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)

			decrypted, stale, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
				return
			}

			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStale {
				t.Errorf("stale = %v, want %v", stale, tt.expectedStale)
			}

			if tt.expectedIndex >= 0 {
				if !bytes.Equal(decrypted, tt.transformers[tt.expectedIndex].Transformer.(*testTransformer).from) {
					t.Errorf("wrong transformer used")
				}
			}
		})
	}
}

// TestTransformerErrorPropagation tests error propagation with overlapping prefixes.
func TestTransformerErrorPropagation(t *testing.T) {
	tests := []struct {
		name         string
		transformers []PrefixTransformer
		incomingData []byte
		expectErr    bool
		matchIndex   int
	}{
		{
			name: "error in first transformer with fallback",
			transformers: []PrefixTransformer{
				{Prefix: []byte("shared:"), Transformer: &testTransformer{err: fmt.Errorf("first failed")}},
				{Prefix: []byte("shared:"), Transformer: &testTransformer{from: []byte("fallback")}},
			},
			incomingData: []byte("shared:data"),
			expectErr:    false, // should fallback to second transformer
			matchIndex:   1,
		},
		{
			name: "both transformers fail with same prefix",
			transformers: []PrefixTransformer{
				{Prefix: []byte("key:"), Transformer: &testTransformer{err: fmt.Errorf("error1")}},
				{Prefix: []byte("key:"), Transformer: &testTransformer{err: fmt.Errorf("error2")}},
			},
			incomingData: []byte("key:data"),
			expectErr:    true,
			matchIndex:   -1,
		},
		{
			name: "identity transformer with error and fallback",
			transformers: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &testTransformer{err: fmt.Errorf("identity failed")}},
				{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("encrypted")}},
			},
			incomingData: []byte("enc:data"),
			expectErr:    false,
			matchIndex:   1,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("default error"), tt.transformers...)

			decrypted, _, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
			} else {
				if err != nil {
					t.Fatalf("unexpected error: %v", err)
				}
				if tt.matchIndex >= 0 && !bytes.Equal(decrypted, tt.transformers[tt.matchIndex].Transformer.(*testTransformer).from) {
					t.Errorf("wrong transformer matched")
				}
			}
		})
	}
}

// TestTransformerToStorage tests the write path with prefix transformers.
func TestTransformerToStorage(t *testing.T) {
	tests := []struct {
		name              string
		data              []byte
		transformers      []PrefixTransformer
		expectErr         bool
		expectedPrefix    []byte
	}{
		{
			name: "write uses first transformer",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &testTransformer{to: []byte("cipher")}},
				{Prefix: []byte("old:"), Transformer: &testTransformer{to: []byte("oldcipher")}},
			},
			expectErr:      false,
			expectedPrefix: []byte("enc:"),
		},
		{
			name: "write error propagates",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &testTransformer{err: fmt.Errorf("encryption failed")}},
			},
			expectErr: true,
		},
		{
			name: "write with empty prefix",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &testTransformer{to: []byte("identity")}},
			},
			expectErr:      false,
			expectedPrefix: []byte{},
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)

			encrypted, err := prefixTrans.TransformToStorage(ctx, tt.data, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
			} else {
				if err != nil {
					t.Fatalf("unexpected error: %v", err)
				}

				// Verify prefix is prepended
				if !bytes.HasPrefix(encrypted, tt.expectedPrefix) {
					t.Errorf("result does not start with prefix %q", string(tt.expectedPrefix))
				}
			}
		})
	}
}

// TestStaleFlagBehavior tests the stale flag behavior with different transformer indices.
func TestStaleFlagBehavior(t *testing.T) {
	tests := []struct {
		name          string
		matchIndex    int
		expectedStale bool
		description   string
	}{
		{
			name:          "first transformer returns not stale",
			matchIndex:    0,
			expectedStale: false,
			description:   "using the latest encryption key",
		},
		{
			name:          "second transformer returns stale",
			matchIndex:    1,
			expectedStale: true,
			description:   "data is encrypted with old key, needs re-encryption",
		},
		{
			name:          "third transformer returns stale",
			matchIndex:    2,
			expectedStale: true,
			description:   "old encryption key, definitely needs refresh",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformers := []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &testTransformer{from: []byte("data")}},
				{Prefix: []byte("v2:"), Transformer: &testTransformer{from: []byte("data")}},
				{Prefix: []byte("v3:"), Transformer: &testTransformer{from: []byte("data")}},
			}

			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), transformers...)

			// Create input with the matching prefix
			prefix := transformers[tt.matchIndex].Prefix
			input := append(prefix, []byte("encrypted")...)

			_, stale, err := prefixTrans.TransformFromStorage(ctx, input, nil)

			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStale {
				t.Errorf("stale = %v, want %v (for %s)", stale, tt.expectedStale, tt.description)
			}
		})
	}
}

// TestEdgeCaseEmptyValues tests edge cases with empty values.
func TestEdgeCaseEmptyValues(t *testing.T) {
	tests := []struct {
		name        string
		data        []byte
		prefix      []byte
		expectErr   bool
		description string
	}{
		{
			name:        "empty data empty prefix",
			data:        []byte{},
			prefix:      []byte{},
			expectErr:   false,
			description: "minimal case",
		},
		{
			name:        "empty data with prefix",
			data:        []byte{},
			prefix:      []byte("prefix:"),
			expectErr:   false,
			description: "prefix but no data",
		},
		{
			name:        "non-empty data empty prefix",
			data:        []byte("data"),
			prefix:      []byte{},
			expectErr:   false,
			description: "identity transformer case",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: tt.prefix, Transformer: &testTransformer{to: tt.data, from: tt.data}},
			)

			encrypted, err := prefixTrans.TransformToStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("TransformToStorage error: %v", err)
			}

			decrypted, _, err := prefixTrans.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage error: %v", err)
			}

			if !bytes.Equal(decrypted, tt.data) {
				t.Errorf("round-trip failed for empty value case")
			}
		})
	}
}

// TestContextPropagation tests that context is correctly propagated to transformers.
func TestContextPropagation(t *testing.T) {
	tests := []struct {
		name        string
		context     Context
		description string
	}{
		{
			name:        "nil context",
			context:     nil,
			description: "no authenticated data",
		},
		{
			name:        "empty context",
			context:     DefaultContext([]byte{}),
			description: "empty authenticated data",
		},
		{
			name:        "context with data",
			context:     DefaultContext([]byte("key:version:namespace")),
			description: "authenticated data with identity info",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			receivedCtx := []Context{}
			capturingTransformer := &capturingTransformer{
				captured: &receivedCtx,
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: []byte("key:"), Transformer: capturingTransformer},
			)

			prefixTrans.TransformToStorage(ctx, []byte("data"), tt.context)

			if len(receivedCtx) != 1 {
				t.Fatalf("expected 1 context, got %d", len(receivedCtx))
			}

			if tt.context == nil && receivedCtx[0] != nil {
				t.Errorf("expected nil context, got %v", receivedCtx[0])
			}

			if tt.context != nil {
				if !bytes.Equal(receivedCtx[0].AuthenticatedData(), tt.context.AuthenticatedData()) {
					t.Errorf("context data mismatch")
				}
			}
		})
	}
}

// TestNewPrefixTransformersErrorDefaulting tests the error handling in NewPrefixTransformers.
func TestNewPrefixTransformersErrorDefaulting(t *testing.T) {
	tests := []struct {
		name              string
		providedErr       error
		expectedErrPrefix string
	}{
		{
			name:              "nil error defaults to generic message",
			providedErr:       nil,
			expectedErrPrefix: "does not match any of the supported transformers",
		},
		{
			name:              "custom error is preserved",
			providedErr:       fmt.Errorf("custom error message"),
			expectedErrPrefix: "custom error message",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(
				tt.providedErr,
				PrefixTransformer{Prefix: []byte("match:"), Transformer: &testTransformer{}},
			)

			// Try to match data with non-matching prefix
			_, _, err := prefixTrans.TransformFromStorage(ctx, []byte("nomatch:data"), nil)

			if err == nil {
				t.Fatalf("expected error, got nil")
			}

			errMsg := err.Error()
			if !bytes.Contains([]byte(errMsg), []byte(tt.expectedErrPrefix)) {
				t.Errorf("error message %q does not contain expected prefix %q", errMsg, tt.expectedErrPrefix)
			}
		})
	}
}

// Helper test transformer that captures context values
type capturingTransformer struct {
	captured *[]Context
}

func (ct *capturingTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	*ct.captured = append(*ct.captured, dataCtx)
	return data, false, nil
}

func (ct *capturingTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	*ct.captured = append(*ct.captured, dataCtx)
	return data, nil
}

// testTransformer is a simple implementation of Transformer for testing
type testTransformer struct {
	from, to                 []byte
	err                      error
	stale                    bool
	receivedFrom, receivedTo []byte
}

func (t *testTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, stale bool, err error) {
	t.receivedFrom = data
	return t.from, t.stale, t.err
}

func (t *testTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, err error) {
	t.receivedTo = data
	return t.to, t.err
}
