// TestMultiplePrefixTransformers tests transformer union with multiple prefixes.
func TestMultiplePrefixTransformers(t *testing.T) {
	tests := []struct {
		name           string
		transformers   []PrefixTransformer
		incomingData   []byte
		expectedIndex  int
		expectedStale  bool
		expectErr      bool
	}{
		{
			name: "first transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("first:encrypted"),
			expectedIndex: 0,
			expectedStale: false,
		},
		{
			name: "second transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("second:encrypted"),
			expectedIndex: 1,
			expectedStale: true, // stale because not using first transformer
		},
		{
			name: "no transformer matches",
			transformers: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &testTransformer{from: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &testTransformer{from: []byte("value2")}},
			},
			incomingData:  []byte("third:encrypted"),
			expectedIndex: -1,
			expectErr:     true,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)

			decrypted, stale, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
				return
			}

			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStale {
				t.Errorf("stale = %v, want %v", stale, tt.expectedStale)
			}

			if tt.expectedIndex >= 0 {
				if !bytes.Equal(decrypted, tt.transformers[tt.expectedIndex].Transformer.(*testTransformer).from) {
					t.Errorf("wrong transformer used")
				}
			}
		})
	}
}

// TestTransformerErrorPropagation tests error propagation with overlapping prefixes.
func TestTransformerErrorPropagation(t *testing.T) {
	tests := []struct {
		name         string
		transformers []PrefixTransformer
		incomingData []byte
		expectErr    bool
		matchIndex   int
	}{
		{
			name: "error in first transformer with fallback",
			transformers: []PrefixTransformer{
				{Prefix: []byte("shared:"), Transformer: &testTransformer{err: fmt.Errorf("first failed")}},
				{Prefix: []byte("shared:"), Transformer: &testTransformer{from: []byte("fallback")}},
			},
			incomingData: []byte("shared:data"),
			expectErr:    false, // should fallback to second transformer
			matchIndex:   1,
		},
		{
			name: "both transformers fail with same prefix",
			transformers: []PrefixTransformer{
				{Prefix: []byte("key:"), Transformer: &testTransformer{err: fmt.Errorf("error1")}},
				{Prefix: []byte("key:"), Transformer: &testTransformer{err: fmt.Errorf("error2")}},
			},
			incomingData: []byte("key:data"),
			expectErr:    true,
			matchIndex:   -1,
		},
		{
			name: "identity transformer with error and fallback",
			transformers: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &testTransformer{err: fmt.Errorf("identity failed")}},
				{Prefix: []byte("enc:"), Transformer: &testTransformer{from: []byte("encrypted")}},
			},
			incomingData: []byte("enc:data"),
			expectErr:    false,
			matchIndex:   1,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("default error"), tt.transformers...)

			decrypted, _, err := prefixTrans.TransformFromStorage(ctx, tt.incomingData, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
			} else {
				if err != nil {
					t.Fatalf("unexpected error: %v", err)
				}
				if tt.matchIndex >= 0 && !bytes.Equal(decrypted, tt.transformers[tt.matchIndex].Transformer.(*testTransformer).from) {
					t.Errorf("wrong transformer matched")
				}
			}
		})
	}
}

// TestTransformerToStorage tests the write path with prefix transformers.
func TestTransformerToStorage(t *testing.T) {
	tests := []struct {
		name              string
		data              []byte
		transformers      []PrefixTransformer
		expectErr         bool
		expectedPrefix    []byte
	}{
		{
			name: "write uses first transformer",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &testTransformer{to: []byte("cipher")}},
				{Prefix: []byte("old:"), Transformer: &testTransformer{to: []byte("oldcipher")}},
			},
			expectErr:      false,
			expectedPrefix: []byte("enc:"),
		},
		{
			name: "write error propagates",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("enc:"), Transformer: &testTransformer{err: fmt.Errorf("encryption failed")}},
			},
			expectErr: true,
		},
		{
			name: "write with empty prefix",
			data: []byte("plaintext"),
			transformers: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &testTransformer{to: []byte("identity")}},
			},
			expectErr:      false,
			expectedPrefix: []byte{},
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)

			encrypted, err := prefixTrans.TransformToStorage(ctx, tt.data, nil)

			if tt.expectErr {
				if err == nil {
					t.Errorf("expected error, got nil")
				}
			} else {
				if err != nil {
					t.Fatalf("unexpected error: %v", err)
				}

				// Verify prefix is prepended
				if !bytes.HasPrefix(encrypted, tt.expectedPrefix) {
					t.Errorf("result does not start with prefix %q", string(tt.expectedPrefix))
				}
			}
		})
	}
}

// TestStaleFlagBehavior tests the stale flag behavior with different transformer indices.
func TestStaleFlagBehavior(t *testing.T) {
	tests := []struct {
		name          string
		matchIndex    int
		expectedStale bool
		description   string
	}{
		{
			name:          "first transformer returns not stale",
			matchIndex:    0,
			expectedStale: false,
			description:   "using the latest encryption key",
		},
		{
			name:          "second transformer returns stale",
			matchIndex:    1,
			expectedStale: true,
			description:   "data is encrypted with old key, needs re-encryption",
		},
		{
			name:          "third transformer returns stale",
			matchIndex:    2,
			expectedStale: true,
			description:   "old encryption key, definitely needs refresh",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformers := []PrefixTransformer{
				{Prefix: []byte("v1:"), Transformer: &testTransformer{from: []byte("data")}},
				{Prefix: []byte("v2:"), Transformer: &testTransformer{from: []byte("data")}},
				{Prefix: []byte("v3:"), Transformer: &testTransformer{from: []byte("data")}},
			}

			prefixTrans := NewPrefixTransformers(fmt.Errorf("no match"), transformers...)

			// Create input with the matching prefix
			prefix := transformers[tt.matchIndex].Prefix
			input := append(prefix, []byte("encrypted")...)

			_, stale, err := prefixTrans.TransformFromStorage(ctx, input, nil)

			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			if stale != tt.expectedStale {
				t.Errorf("stale = %v, want %v (for %s)", stale, tt.expectedStale, tt.description)
			}
		})
	}
}

