			expectErr:         false,
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			testTransformer := &testTransformer{
				from: tt.expectedDecrypted,
				to:   []byte("cipher"), // the part after the prefix
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: tt.prefix, Transformer: testTransformer},
			)

			// Test encryption with prefix
			encrypted, err := prefixTrans.TransformToStorage(ctx, tt.data, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			if !bytes.Equal(encrypted, tt.expectedEncrypted) {
				t.Errorf("encrypted = %v, want %v", encrypted, tt.expectedEncrypted)
			}

			// Test decryption with prefix
			decrypted, stale, err := prefixTrans.TransformFromStorage(ctx, encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(decrypted, tt.expectedDecrypted) {
				t.Errorf("decrypted = %v, want %v", decrypted, tt.expectedDecrypted)
			}

			if stale {
				t.Errorf("expected stale=false for matching first prefix, got true")
			}
		})
	}
}

// TestPrefixTransformerMismatchedPrefix tests error handling for mismatched prefixes.
func TestPrefixTransformerMismatchedPrefix(t *testing.T) {
