// TestContextPropagation tests that context is correctly propagated to transformers.
func TestContextPropagation(t *testing.T) {
	tests := []struct {
		name        string
		context     Context
		description string
	}{
		{
			name:        "nil context",
			context:     nil,
			description: "no authenticated data",
		},
		{
			name:        "empty context",
			context:     DefaultContext([]byte{}),
			description: "empty authenticated data",
		},
		{
			name:        "context with data",
			context:     DefaultContext([]byte("key:version:namespace")),
			description: "authenticated data with identity info",
		},
	}

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			receivedCtx := []Context{}
			capturingTransformer := &capturingTransformer{
				captured: &receivedCtx,
			}

			prefixTrans := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: []byte("key:"), Transformer: capturingTransformer},
			)

			prefixTrans.TransformToStorage(ctx, []byte("data"), tt.context)

			if len(receivedCtx) != 1 {
				t.Fatalf("expected 1 context, got %d", len(receivedCtx))
			}

			if tt.context == nil && receivedCtx[0] != nil {
				t.Errorf("expected nil context, got %v", receivedCtx[0])
			}

			if tt.context != nil {
				if !bytes.Equal(receivedCtx[0].AuthenticatedData(), tt.context.AuthenticatedData()) {
					t.Errorf("context data mismatch")
				}
			}
		})
	}
}

// TestNewPrefixTransformersErrorDefaulting tests the error handling in NewPrefixTransformers.
func TestNewPrefixTransformersErrorDefaulting(t *testing.T) {
	tests := []struct {
