				PrefixTransformer{Prefix: []byte("match:"), Transformer: &testTransformer{}},
			)

			// Try to match data with non-matching prefix
			_, _, err := prefixTrans.TransformFromStorage(ctx, []byte("nomatch:data"), nil)

			if err == nil {
				t.Fatalf("expected error, got nil")
			}

			errMsg := err.Error()
